import xml.etree.ElementTree as ET
from typing import Dict

def parse_xml_config(file_path: str) -> Dict[str, str]:
    tree = ET.parse(file_path)
    root = tree.getroot()
    
    settings = {}
    for setting in root.findall(".//setting"):
        key = setting.attrib["name"]
        value = setting.text
        settings[key] = value
        
    return settings